fun solve(nums: Array<Long>): Long {
    var totalMinXSum: Long = 0L
    val n = nums.size

    for (i in 0 until n - 1) {
        // We require nums'[i] <= nums'[i+1]
        // nums[i] + S_i <= nums[i+1] + S_{i+1}
        // S_{i+1} - S_i >= nums[i] - nums[i+1]

        // If nums[i] > nums[i+1], then nums[i] - nums[i+1] > 0.
        // We need S_{i+1} - S_i >= deficit, where deficit = nums[i] - nums[i+1].
        // This means the total increase applied to nums[i+1] must be at least 'deficit' more than to nums[i].

        if (nums[i] > nums[i+1]) {
            val deficit = nums[i] - nums[i+1]
            // The minimum total cost is the sum of these necessary relative increases.
            totalMinXSum += deficit
        }
    }

    return totalMinXSum
}
